157→                {
158→                    c.OAuthUsePkce();
159→                    c.OAuthClientId(oneportalConfig.AADAuthAppId);
160→                });
161→            }
162→
163→            app.UseExceptionHandler(
164→                options =>
165→                {
166→                    options.Run(
167→                        async context =>
168→                        {
169→                            context.Response.StatusCode = (int)HttpStatusCode.InternalServerError;
170→                            var exContext = context.Features.Get<IExceptionHandlerFeature>();
171→                            if (exContext != null)
172→                            {
173→                                if (exContext.Error is UserException)
174→                                {
175→                                    context.Response.StatusCode = UserException.UserErrorStatusCode;
176→                                    await context.Response.WriteAsJsonAsync((exContext.Error as UserException)!.GetUserError()).ConfigureAwait(false);
177→                                }
178→                                else
179→                                {
180→                                    throw exContext.Error;
181→                                }
182→                            }
183→                        });
184→                });
185→
186→            app.UseEndpoints(endpoints =>
187→            {
188→                if (!oneportalConfig.EnableProxy)
189→                {
190→                    var pipeline = endpoints.CreateApplicationBuilder().Build();
191→                    endpoints.Map("/swagger", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
192→                    endpoints.Map("/swagger/index.html", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
193→                    endpoints.Map("/swagger/v1/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
194→                    endpoints.Map("/swagger/{documentName}/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
195→                    endpoints.MapRazorPages();
