206→
207→            if (!oneportalConfig.EnableProxy)
208→            {
209→                app.UseSpa(spa =>
210→                {
211→                    spa.Options.SourcePath = "ClientApp";
212→                    if (envProps!.Environment == EnvironmentEnum.DevMachine)
213→                    {
214→                        spa.UseReactDevelopmentServer(npmScript: "start");
215→                    }
216→                });
217→            }
218→
219→            app.UseWarmup();
220→        }
221→    }
