 8→    /// <summary>
 9→    /// oneportal config, maps to 'Config/1p.config.json'.
10→    /// </summary>
11→    public class OnePortalConfig
12→    {
13→        /// <summary>
14→        /// Gets or sets a value indicating whether to initialize as proxy service.
15→        /// </summary>
16→        public bool EnableProxy { get; set; } = false;
17→
18→        /// <summary>
19→        /// Gets or sets destination url for proxy.
20→        /// </summary>
21→        public string ProxyDestUrl { get; set; } = string.Empty;
22→
23→        /// <summary>
24→        /// Gets or sets a value indicating whether to skip ssl validation in proxy handling.
25→        /// </summary>
26→        public bool SkipProxySslValidation { get; set; } = false;
27→
28→        /// <summary>
29→        /// Gets or sets azure app id used for bearer token authentication in backend.
30→        /// </summary>
31→        public string AADAuthAppId { get; set; } = Secret.Constants.EqAppId;
32→
33→        /// <summary>
34→        /// Gets or sets a value indicating whether to enable API access using tokens issued from both PME and Msft tenants.
35→        /// NOTE: pre-requirements for enabling PME access:
36→        ///         1-Azure App Id specified via 'AADAuthAppId' config property is required to be multitenant (PME -> Msft)
37→        ///         2-Client must issue used token with scope 'api://app_id/.default'.
38→        /// </summary>
39→        public bool EnablePmeAndMsftApiAccess { get; set; } = false;
40→
41→        /// <summary>
42→        /// Overrides parameter values from corresponding environment variables.
43→        /// ex: OnePortalConfig.EnableProxy=true.
44→        /// </summary>
45→        public void OverrideConfigFromEnvVars()
46→        {
47→            Type t = this.GetType();
48→            foreach (PropertyInfo info in t.GetProperties())
49→            {
50→                var envVarName = $"{t.Name}.{info.Name}";
51→                var envVarValue = Environment.GetEnvironmentVariable(envVarName);
52→                if (!string.IsNullOrEmpty(envVarValue) && info.CanWrite)
53→                {
54→                    if (info.PropertyType == typeof(string))
55→                    {
56→                        info.SetValue(this, envVarValue);
57→                    }
58→                    else if (info.PropertyType == typeof(bool))
59→                    {
60→                        info.SetValue(this, bool.Parse(envVarValue));
61→                    }
62→                    else
63→                    {
64→                        throw new NotSupportedException($"Unsupported type {info.PropertyType}");
65→                    }
66→                }
67→            }
68→        }
69→    }
70→}

